import React, { memo, useCallback } from "react";
import { Pressable, View, Text } from "react-native";
import type { SelectButtonProps } from "./SelectButton.types";
import { resolveThemeTokenForNative } from '../../Factory/helpers/style';
export * from './SelectButton.types'
export const SelectButton = memo(function SelectButton<T = any>({
                                                                  value,
                                                                  options,
                                                                  multiple = false,
                                                                  allowEmpty = true,
                                                                  unselectable = true,
                                                                  disabled = false,
                                                                  invalid = false,

                                                                  optionLabel = "label",
                                                                  optionValue = "value",
                                                                  optionDisabled,

                                                                  itemTemplate,
                                                                  onChange,

                                                                  style,
                                                                  unstyled = false,
                                                                }: SelectButtonProps<T>) {
  const isSelected = useCallback(
    (optionValue: any) => {
      if (multiple && Array.isArray(value)) {
        return value.some(v => v === optionValue);
      }
      return value === optionValue;
    },
    [value, multiple]
  );

  const resolveDisabled = (option: any) => {
    if (typeof optionDisabled === "function") {
      return optionDisabled(option);
    }
    if (typeof optionDisabled === "string") {
      return !!option?.[optionDisabled];
    }
    return !!option?.disabled;
  };

  const handlePress = (option: any) => {
    if (disabled || resolveDisabled(option)) return;

    const optionVal = option?.[optionValue];
    const selected = isSelected(optionVal);

    let nextValue: any;

    if (multiple) {
      const current = Array.isArray(value) ? value : [];
      if (selected) {
        if (!unselectable || (!allowEmpty && current.length === 1)) return;
        nextValue = current.filter(v => v !== optionVal);
      } else {
        nextValue = [...current, optionVal];
      }
    } else {
      if (selected) {
        if (!unselectable || !allowEmpty) return;
        nextValue = null;
      } else {
        nextValue = optionVal;
      }
    }

    onChange?.({
      value: nextValue,
      checked: !selected,
    });
  };

  return (
    <View
      style={[
        !unstyled && {
          flexDirection: "row",
          borderWidth: 1,
          borderRadius: 6,
          borderColor: invalid ? resolveThemeTokenForNative('red.500') : resolveThemeTokenForNative('gray.300'),
          overflow: "hidden",
        },
        style,
      ]}
    >
      {options.map((option, index) => {
        const optionVal = option?.[optionValue];
        const selected = isSelected(optionVal);
        const optionIsDisabled = disabled || resolveDisabled(option);

        return (
          <Pressable
            key={optionVal ?? index}
            onPress={() => handlePress(option)}
            disabled={optionIsDisabled}
            style={[
              !unstyled && {
                paddingHorizontal: 12,
                paddingVertical: 8,
                backgroundColor: selected ? resolveThemeTokenForNative('primary') : "transparent",
                opacity: optionIsDisabled ? 0.5 : 1,
                borderRightWidth: index < options.length - 1 ? 1 : 0,
                borderColor: resolveThemeTokenForNative('gray.300'),
              },
            ]}
          >
            {itemTemplate ? (
              itemTemplate(option, selected)
            ) : (
              <View style={{ flexDirection: "row", alignItems: "center", gap: 6 }}>
                {option.icon}
                <Text
                  style={{
                    color: selected ? "#fff" : resolveThemeTokenForNative('gray.900'),
                    fontWeight: selected ? "600" : "400",
                  }}
                >
                  {option?.[optionLabel]}
                </Text>
              </View>
            )}
          </Pressable>
        );
      })}
    </View>
  );
});
